struct node {
	T value;
	node<T>* next;
};
template<typename T>
void push_back(node<T>** head_ref,T new_data)
{
	node<T>* new_node = new node<T>;
	new_node->value = new_data;
	new_node->next = NULL;
	node<T>* last = *head_ref;
	if (*head_ref == NULL)
	{
		*head_ref = new_node;
		return;
	}
	while (last->next!=NULL)
		last = last->next;
	last->next = new_node;
}
template<typename T>
void reverse_nodes(node<T>** head_ref) {
	node<T>* first = *head_ref;
	node<T>* second = NULL;
	node<T>* third = NULL;
	while (first) {
		third = second;
		second = first;
		first = first->next;
		second->next = third;
	}
	*head_ref = second;
}
