{
public:
    int first; int last; int size;
    T* data;
    array_t(int size): first(0), last(size), size(size)
    {
        data = new T[size];
        for(int i = 0; i < size; ++i)
            data[i]  = i;
    }
    void fill(const T value) { for(int i = 0; i < size; ++i) data[i] = value; }
    array_t<T>& operator=(const T value)
    {
        fill(value);
        return *this;
    }
};
